+      ...(this.timeout ? ['--timeout', String(this.timeout)] : []),
+      ...(!this.headless ? ['--headed'] : []),
+      ...(this.executablePath ? ['--executable-path', this.executablePath] : []),
+      ...(this.proxy ? ['--proxy-server', this.proxy] : []),
